SELECT ?series ?seriesLabel ?episodes WHERE {
  ?series wdt:P31 wd:Q117467246;
         wdt:P17 wd:Q30;
         wdt:P1171 ?episodes.
  ?series rdfs:label ?seriesLabel.
  FILTER(LANG(?seriesLabel) = 'en').
} ORDER BY DESC(?episodes) LIMIT 5

SELECT ?series ?seriesLabel ?episodes WHERE {
  ?series wdt:P31 wd:Q117467246;
          wdt:P17 wd:Q30;
          wdt:P1171 ?episodes.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
